# Brecho de Luxo - Parte 2/3
import os, base64, gzip
base = os.path.dirname(os.path.abspath(__file__))
print("Instalando parte 2/3...")
FILES = [
  ('src\\\\app\\\\layout.tsx', ''),
  ('src\\\\app\\\\page.tsx', ''),
  ('src\\\\app\\\\admin-loja\\\\page.tsx', ''),
  ('src\\\\app\\\\contato\\\\page.tsx', ''),
  ('src\\\\app\\\\api\\\\webhook\\\\mercadopago\\\\route.ts', ''),
  ('src\\\\app\\\\api\\\\produtos\\\\route.ts', ''),
  ('src\\\\app\\\\api\\\\pagamento\\\\route.ts', ''),
  ('src\\\\app\\\\loja\\\\page.tsx', ''),
  ('src\\\\app\\\\loja\\\\[id]\\\\page.tsx', ''),
]
ok = 0
for rel_path, data in FILES:
    try:
        dest = os.path.join(base, rel_path)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        c = gzip.decompress(base64.b64decode(data)).decode("utf-8")
        with open(dest, "w", encoding="utf-8", newline="\n") as f: f.write(c)
        ok += 1
    except Exception as e: print("ERRO:", rel_path, e)
print(f"Parte 2: {ok}/9 OK")